(window.webpackJsonp=window.webpackJsonp||[]).push([[217],{844:function(n,e){n.exports=' \x3c!-- \ntitle: 02-Rust基础\nsort: \n--\x3e \n\n### 结构体\n\n```rust\nstruct User {\n    username: String,\n    email: String,\n    active: bool,\n}\n\nstruct Color(u8,u8,u8);\n\nfn build_user(username: String, email: String) {\n    let mut a_user = User {\n        username: username,\n        email: email,\n        active: false,\n    };\n    a_user.active = true;\n    // 基于实例的更新语法\n    User{\n      username: String::from("fzf404"),\n      ..a_user\n    };\n    // Tuple Struct\n    let white = Color(255,255,255);\n}\n\n// 打印结构体\n#[derive(Debug)]\nprintln!("{:#?}",a_user);\n```\n\n#### 定义方法\n\n```rust\n// 为结构体定义方法\nstruct Rectangle {\n    width: u32,\n    height: u32,\n}\n\nimpl Rectangle{\n  fn area(&self) -> u32{\n    self.width * self.height\n  }\n  // 关联函数\n  fn square(size: u32) -> Rectangle {\n    Rectangle {\n      height: size,\n      width: size,\n    }\n  }\n}\n// 将关联函数用于构造器\nlet a_square = Rectangle::square(30);\nprintln!("{}",a_square.area())\n```\n\n### 枚举\n\n```rust\nenum IPAddr {\n    v4(u8, u8, u8, u8),\n    v6(String),\n}\nlet localv4 = IPAddr::v4(127, 0, 0, 1);\nlet localv6 = IPAddr::v6(String::from("::1"));\n\n// 为枚举定义方法\nimpl IPAddr{\n  fn call(&self) {}\n}\n```\n\n#### Option\n\n> Rust中没有None类型，使用Option创建。\n>\n> 这样当变量不为`Option<T>`类型时，一定不为空。\n\n```rust\nlet x: Option<i8> = None;\nlet y = Some(5);\n```\n\n'}}]);